/**
 * Aura Alpha — In-App Purchase (IAP) Service
 *
 * Unified purchase layer that handles both:
 *   - iOS: StoreKit 2 native purchases via Capacitor plugin
 *   - Web: Stripe checkout via existing backend routes
 *
 * This service complements (does not replace) the existing Stripe billing
 * flow. On web it delegates to the Stripe checkout endpoints. On native
 * iOS it uses StoreKit for the purchase then sends the signed transaction
 * to the backend for server-side verification.
 *
 * Usage:
 *   import iapService from '@/services/iapService';
 *
 *   // Initialize once at app startup (e.g., in App.jsx useEffect)
 *   await iapService.initialize();
 *
 *   // Check platform
 *   if (iapService.isNative()) { ... }
 *
 *   // Purchase a platform subscription
 *   const result = await iapService.purchaseSubscription(
 *     'platform', 'professional', 'monthly'
 *   );
 *
 *   // Restore previous purchases (iOS)
 *   const restored = await iapService.restorePurchases();
 */

import StoreKit, { PRODUCT_IDS } from '@/plugins/StoreKitPlugin';
import { getApiBase } from '@/utils/platform';

// ── Auth helper (mirrors BillingDashboardPage pattern) ──

function authHeaders() {
  try {
    const token = localStorage.getItem('aura_token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  } catch {
    return {};
  }
}

async function apiFetch(path, opts = {}) {
  const base = getApiBase();
  const headers = {
    ...authHeaders(),
    'Content-Type': 'application/json',
    ...(opts.headers || {}),
  };
  const res = await fetch(`${base}${path}`, { ...opts, headers });
  if (!res.ok) {
    const text = await res.text();
    let detail = `HTTP ${res.status}`;
    try {
      const json = JSON.parse(text);
      detail = json.detail || json.error || detail;
    } catch { /* use status text */ }
    throw new Error(detail);
  }
  return res.json();
}

// ── Product ID mapping ──
// Maps (system, tier, period) to App Store product IDs.
// Must stay in sync with prodesk/phase2/app/services/appstore_pricing.py

const PRODUCT_MAP = {
  platform: {
    // New tier names
    trader:        { monthly: 'cc.auraalpha.platform.starter.monthly',       annual: 'cc.auraalpha.platform.starter.annual' },
    pro:           { monthly: 'cc.auraalpha.platform.pro.monthly',           annual: 'cc.auraalpha.platform.pro.annual' },
    institutional: { monthly: 'cc.auraalpha.platform.institutional.monthly', annual: 'cc.auraalpha.platform.institutional.annual' },
    // Legacy aliases (keep for backwards compat)
    starter:       { monthly: 'cc.auraalpha.platform.starter.monthly',       annual: 'cc.auraalpha.platform.starter.annual' },
    professional:  { monthly: 'cc.auraalpha.platform.pro.monthly',           annual: 'cc.auraalpha.platform.pro.annual' },
    power_user:    { monthly: 'cc.auraalpha.platform.power.monthly',         annual: 'cc.auraalpha.platform.power.annual' },
  },
  ai: {
    basic:      { monthly: 'cc.auraalpha.ai.basic.monthly' },
    pro:        { monthly: 'cc.auraalpha.ai.pro.monthly' },
    enterprise: { monthly: 'cc.auraalpha.ai.enterprise.monthly' },
  },
};

// Reverse map: product ID -> { system, tier, period }
const PRODUCT_REVERSE = {};
for (const [system, tiers] of Object.entries(PRODUCT_MAP)) {
  for (const [tier, periods] of Object.entries(tiers)) {
    for (const [period, productId] of Object.entries(periods)) {
      PRODUCT_REVERSE[productId] = { system, tier, period };
    }
  }
}

// ── Service state ──

let _initialized = false;
let _products = []; // App Store products fetched from StoreKit
let _entitlements = []; // Active entitlements
let _transactionListeners = [];
let _unsubTransactionUpdate = null;

// ── IAP Service ──

const iapService = {
  /**
   * Whether the app is running on a native platform (iOS/Android).
   * When false, all purchase flows should use Stripe web checkout instead.
   */
  isNative() {
    return StoreKit.isNative();
  },

  /**
   * Current platform string: "ios" | "android" | "web"
   */
  getPlatform() {
    return StoreKit.platform();
  },

  /**
   * Initialize the IAP service. Call once at app startup.
   * - On iOS: fetches products from App Store, loads entitlements, starts
   *   listening for transaction updates.
   * - On web: no-op (Stripe flows don't need initialization).
   */
  async initialize() {
    if (_initialized) return;
    _initialized = true;

    if (!StoreKit.isNative()) {
      return; // Web — nothing to initialize
    }

    try {
      // Fetch available products from App Store
      const { products } = await StoreKit.getProducts();
      _products = products || [];

      // Check current entitlements (active subscriptions)
      const { entitlements } = await StoreKit.getEntitlements();
      _entitlements = entitlements || [];

      // If user has active entitlements, sync with backend
      if (_entitlements.length > 0) {
        await this._syncEntitlementsToBackend(_entitlements);
      }

      // Listen for transaction updates (renewals, grace periods, revocations)
      _unsubTransactionUpdate = StoreKit.onTransactionUpdate((event) => {
        this._handleTransactionUpdate(event);
      });
    } catch (err) {
      console.warn('[IAP] Initialization error (non-fatal):', err.message);
    }
  },

  /**
   * Clean up listeners. Call on app teardown if needed.
   */
  destroy() {
    if (_unsubTransactionUpdate) {
      _unsubTransactionUpdate();
      _unsubTransactionUpdate = null;
    }
    _transactionListeners = [];
    _initialized = false;
  },

  /**
   * Get the App Store product ID for a given system/tier/period.
   * @param {string} system - "platform" or "ai"
   * @param {string} tier - e.g. "professional", "basic"
   * @param {string} period - "monthly" or "annual"
   * @returns {string|null}
   */
  getProductId(system, tier, period = 'monthly') {
    return PRODUCT_MAP[system]?.[tier]?.[period] || null;
  },

  /**
   * Get the fetched App Store products (populated after initialize()).
   * Each product has: { productId, displayName, description, displayPrice, price, ... }
   * @returns {Array}
   */
  getProducts() {
    return _products;
  },

  /**
   * Get the display price for a product from the App Store.
   * Falls back to null if not available (web, or product not found).
   * @param {string} productId
   * @returns {string|null} e.g. "$114.99"
   */
  getDisplayPrice(productId) {
    const product = _products.find((p) => p.productId === productId);
    return product ? (product.displayPrice || product.price) : null;
  },

  /**
   * Get current active entitlements (loaded at init, refreshed after purchase).
   * @returns {Array}
   */
  getEntitlements() {
    return _entitlements;
  },

  /**
   * Purchase a subscription.
   *
   * On iOS: triggers native StoreKit purchase, then sends the signed
   * transaction to the backend for verification and activation.
   *
   * On web: initiates a Stripe checkout session and redirects the browser.
   * Returns { checkout_url } for the caller to redirect.
   *
   * @param {string} system - "platform" or "ai"
   * @param {string} tier - e.g. "professional", "starter"
   * @param {string} period - "monthly" or "annual"
   * @param {object} [opts] - Additional options
   * @param {string} [opts.promoCode] - Promo code (web/Stripe only)
   * @returns {Promise<object>} Result of purchase or checkout
   */
  async purchaseSubscription(system, tier, period = 'monthly', opts = {}) {
    if (StoreKit.isNative()) {
      return this._purchaseNative(system, tier, period);
    }
    return this._purchaseWeb(system, tier, period, opts);
  },

  /**
   * Restore previous App Store purchases (iOS only).
   * Syncs restored entitlements with the backend.
   *
   * On web: returns { restored: false, message: 'Use Stripe billing portal' }
   *
   * @returns {Promise<{restored: boolean, tier?: string, entitlements?: Array}>}
   */
  async restorePurchases() {
    if (!StoreKit.isNative()) {
      return {
        restored: false,
        message: 'Restore purchases is only available in the iOS app. Use the billing portal to manage your web subscription.',
      };
    }

    const result = await StoreKit.restorePurchases();
    const entitlements = result.entitlements || [];
    _entitlements = entitlements;

    if (entitlements.length === 0) {
      return { restored: false, message: 'No active subscriptions found.' };
    }

    // Send the latest entitlement to backend for verification
    const latest = entitlements[0];
    const verification = await this._validateReceipt({
      system: this._systemFromProductId(latest.productId),
      productId: latest.productId,
      transactionId: latest.transactionId,
      originalTransactionId: latest.originalTransactionId,
      jwsRepresentation: latest.jwsRepresentation || '',
      isRestore: true,
    });

    return {
      restored: true,
      tier: verification.tier,
      entitlements,
    };
  },

  /**
   * Register a listener for purchase/transaction events.
   * @param {Function} callback - receives { type, productId, tier, error }
   * @returns {Function} unsubscribe
   */
  onPurchaseEvent(callback) {
    _transactionListeners.push(callback);
    return () => {
      _transactionListeners = _transactionListeners.filter((cb) => cb !== callback);
    };
  },

  // ── Internal methods ──

  /**
   * Native iOS purchase flow via StoreKit 2.
   */
  async _purchaseNative(system, tier, period) {
    const productId = this.getProductId(system, tier, period);
    if (!productId) {
      throw new Error(`Unknown product: ${system}/${tier}/${period}`);
    }

    // 1. Initiate the native StoreKit purchase (shows Apple purchase sheet)
    let result;
    try {
      result = await StoreKit.purchase(productId);
    } catch (err) {
      // User cancelled or StoreKit error
      this._emitEvent({ type: 'purchase_failed', productId, error: err.message });
      throw err;
    }

    // 2. Send the signed transaction to our backend for verification
    const verification = await this._validateReceipt({
      system,
      productId,
      transactionId: result.transactionId,
      originalTransactionId: result.originalTransactionId,
      jwsRepresentation: result.jwsRepresentation || '',
      environment: result.environment || 'production',
      isRestore: false,
    });

    // 3. Refresh entitlements
    try {
      const { entitlements } = await StoreKit.getEntitlements();
      _entitlements = entitlements || [];
    } catch { /* non-fatal */ }

    this._emitEvent({ type: 'purchase_success', productId, tier: verification.tier });
    return verification;
  },

  /**
   * Web purchase flow via Stripe checkout.
   */
  async _purchaseWeb(system, tier, period, opts) {
    if (system === 'platform') {
      // Platform subscription via Stripe
      const body = {
        tier,
        billing_period: period === 'annual' ? 'annual' : 'monthly',
      };
      if (opts.promoCode) {
        body.promo_code = opts.promoCode.trim().toUpperCase();
      }
      const data = await apiFetch('/billing/platform/checkout', {
        method: 'POST',
        body: JSON.stringify(body),
      });
      if (data.checkout_url) {
        this._emitEvent({ type: 'checkout_redirect', productId: null, tier });
        window.location.href = data.checkout_url;
        return data;
      }
      throw new Error(data.detail || data.error || 'Could not start checkout');
    }

    if (system === 'ai') {
      // AI subscription via Stripe
      const data = await apiFetch('/subscriptions/checkout', {
        method: 'POST',
        body: JSON.stringify({ tier }),
      });
      if (data.checkout_url) {
        this._emitEvent({ type: 'checkout_redirect', productId: null, tier });
        window.location.href = data.checkout_url;
        return data;
      }
      throw new Error(data.detail || data.error || 'Could not start checkout');
    }

    throw new Error(`Unknown billing system: ${system}`);
  },

  /**
   * Send a receipt/transaction to the backend for server-side validation.
   * The backend verifies the JWS, checks with Apple's Server API if configured,
   * and activates/updates the subscription.
   */
  async _validateReceipt({ system, productId, transactionId, originalTransactionId, jwsRepresentation, environment, isRestore }) {
    const endpoint = isRestore
      ? '/billing/appstore/restore'
      : '/billing/appstore/verify-receipt';

    const payload = {
      product_id: productId,
      transaction_id: transactionId || '',
      original_transaction_id: originalTransactionId || '',
      signed_transaction: jwsRepresentation || '',
      environment: environment || 'production',
      system: system || 'platform',
    };

    return apiFetch(endpoint, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
  },

  /**
   * Sync active entitlements with the backend (called on init if user
   * has active subscriptions — handles renewals that happened while
   * the app was closed).
   */
  async _syncEntitlementsToBackend(entitlements) {
    if (!entitlements || entitlements.length === 0) return;

    try {
      for (const ent of entitlements) {
        const system = this._systemFromProductId(ent.productId);
        await this._validateReceipt({
          system,
          productId: ent.productId,
          transactionId: ent.transactionId,
          originalTransactionId: ent.originalTransactionId,
          jwsRepresentation: ent.jwsRepresentation || '',
          isRestore: false,
        });
      }
    } catch (err) {
      console.warn('[IAP] Entitlement sync failed (non-fatal):', err.message);
    }
  },

  /**
   * Handle a transaction update from StoreKit (renewal, revocation, etc).
   */
  async _handleTransactionUpdate(event) {
    const { transactionId, productId, action } = event || {};

    if (action === 'revoked' || action === 'expired') {
      this._emitEvent({ type: 'subscription_expired', productId, action });
      // Refresh entitlements
      try {
        const { entitlements } = await StoreKit.getEntitlements();
        _entitlements = entitlements || [];
      } catch { /* non-fatal */ }
      return;
    }

    // Renewal or other update — verify with backend
    if (transactionId && productId) {
      try {
        const system = this._systemFromProductId(productId);
        await this._validateReceipt({
          system,
          productId,
          transactionId,
          originalTransactionId: event.originalTransactionId || '',
          jwsRepresentation: event.jwsRepresentation || '',
          isRestore: false,
        });
        this._emitEvent({ type: 'subscription_renewed', productId });
      } catch (err) {
        console.warn('[IAP] Transaction update sync failed:', err.message);
      }
    }

    // Refresh entitlements
    try {
      const { entitlements } = await StoreKit.getEntitlements();
      _entitlements = entitlements || [];
    } catch { /* non-fatal */ }
  },

  /**
   * Determine which billing system a product belongs to from its ID.
   */
  _systemFromProductId(productId) {
    const info = PRODUCT_REVERSE[productId];
    return info ? info.system : 'platform';
  },

  /**
   * Emit a purchase event to all registered listeners.
   */
  _emitEvent(event) {
    for (const cb of _transactionListeners) {
      try {
        cb(event);
      } catch (err) {
        console.error('[IAP] Listener error:', err);
      }
    }
  },
};

export default iapService;
export { PRODUCT_MAP, PRODUCT_REVERSE, PRODUCT_IDS };
