/**
 * StoreKit 2 Capacitor Plugin Bridge — Aura Alpha
 * Registers a native plugin that wraps StoreKit 2 on iOS.
 * On web, provides stubs that return appropriate errors/empty results.
 *
 * The native Swift implementation (StoreKitPlugin.swift) must be added
 * to the iOS project under ios/App/App/Plugins/ and registered in
 * AppDelegate or via Capacitor plugin auto-detection.
 */
import { registerPlugin, Capacitor } from '@capacitor/core';

// ── All App Store product IDs for Aura Alpha ──
// These must match what is registered in App Store Connect.
// See: prodesk/phase2/app/services/appstore_pricing.py
const PRODUCT_IDS = [
  // Platform subscriptions
  'cc.auraalpha.platform.starter.monthly',
  'cc.auraalpha.platform.starter.annual',
  'cc.auraalpha.platform.pro.monthly',
  'cc.auraalpha.platform.pro.annual',
  'cc.auraalpha.platform.power.monthly',
  'cc.auraalpha.platform.power.annual',
  'cc.auraalpha.platform.institutional.monthly',
  'cc.auraalpha.platform.institutional.annual',
  // AI subscriptions
  'cc.auraalpha.ai.basic.monthly',
  'cc.auraalpha.ai.pro.monthly',
  'cc.auraalpha.ai.enterprise.monthly',
];

// Register native plugin (Swift implementation on iOS)
const StoreKitNative = registerPlugin('StoreKitPlugin');

/**
 * Platform-aware StoreKit bridge.
 * On iOS: delegates to native StoreKit 2 via Capacitor plugin.
 * On web: returns stubs so the UI can gracefully degrade to Stripe checkout.
 */
const StoreKit = {
  /** Whether the app is running in a native iOS/Android shell. */
  isNative: () => Capacitor.isNativePlatform(),

  /** Current platform: "ios" | "android" | "web" */
  platform: () => Capacitor.getPlatform(),

  /**
   * Fetch available products from the App Store.
   * @returns {Promise<{products: Array}>}
   */
  async getProducts() {
    if (!Capacitor.isNativePlatform()) {
      return { products: [] };
    }
    return StoreKitNative.getProducts({ productIds: PRODUCT_IDS });
  },

  /**
   * Purchase a subscription product by ID.
   * Triggers the native StoreKit purchase sheet.
   * @param {string} productId - App Store product ID
   * @returns {Promise<{transactionId, originalTransactionId, jwsRepresentation, environment}>}
   */
  async purchase(productId) {
    if (!Capacitor.isNativePlatform()) {
      throw new Error('In-app purchases are only available in the iOS app.');
    }
    return StoreKitNative.purchase({ productId });
  },

  /**
   * Restore previous purchases.
   * @returns {Promise<{entitlements: Array}>}
   */
  async restorePurchases() {
    if (!Capacitor.isNativePlatform()) {
      throw new Error('Restore is only available in the iOS app.');
    }
    return StoreKitNative.restorePurchases();
  },

  /**
   * Get current active entitlements (subscriptions).
   * @returns {Promise<{entitlements: Array}>}
   */
  async getEntitlements() {
    if (!Capacitor.isNativePlatform()) {
      return { entitlements: [] };
    }
    return StoreKitNative.getEntitlements();
  },

  /**
   * Listen for transaction updates (renewals, revocations, etc).
   * The callback fires whenever StoreKit delivers a transaction update.
   * @param {Function} callback - receives { transactionId, productId, action }
   * @returns {Function} unsubscribe function
   */
  onTransactionUpdate(callback) {
    if (!Capacitor.isNativePlatform()) {
      return () => {}; // no-op unsubscribe
    }
    const handle = StoreKitNative.addListener('transactionUpdate', callback);
    return () => handle.remove();
  },
};

export { PRODUCT_IDS };
export default StoreKit;
